// Playbook ids + titles are generated from the concierge skills dir — see
// playbookManifest.generated.ts (regenerated by scripts/copy-instructions.ts).
// This module re-exports them and adds the fixed URI scheme. It stays free of
// `.md` imports so it's safe to load from the tsx schema-generation script via
// src/schema/tool-inputs.ts.
import { type PlaybookId, PLAYBOOK_IDS, PLAYBOOK_TITLES } from './playbookManifest.generated'

export { type PlaybookId, PLAYBOOK_IDS, PLAYBOOK_TITLES }

// Fixed URI scheme, declared once. The resolver tool accepts a playbook by a
// bare id or by its `<PLAYBOOK_URI_PREFIX><id>` URI form; the schema describe and
// the resolver both derive from this constant.
export const PLAYBOOK_URI_PREFIX = 'posthog://agent-platform/playbooks/'

export const playbookUri = (id: PlaybookId): string => `${PLAYBOOK_URI_PREFIX}${id}`

export const PLAYBOOK_URIS: readonly string[] = PLAYBOOK_IDS.map(playbookUri)

/**
 * Normalize a caller-supplied reference (bare id or full `<PLAYBOOK_URI_PREFIX><id>`
 * URI) to a known PlaybookId, or `undefined` if it matches no playbook.
 */
export function playbookIdFromRef(ref: string): PlaybookId | undefined {
    const candidate = ref.startsWith(PLAYBOOK_URI_PREFIX) ? ref.slice(PLAYBOOK_URI_PREFIX.length) : ref
    return (PLAYBOOK_IDS as readonly string[]).includes(candidate) ? (candidate as PlaybookId) : undefined
}
